43	}
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const percentOf = (amount: number, percent: number): number =>
48	  (amount * percent) / PERCENT_BASE;
49	
50	const percentIf = (condition: boolean, base: number, percent: number): number =>
51	  condition ? percentOf(base, percent) : 0;
52	
53	const itemBasePremium = (item: Item): number => {
54	  const base = BASE_PREMIUM[item.type];
55	  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
56	  const highEnchantment = percentIf(
57	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
58	    base,
59	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
60	  );
61	  return base + curse + highEnchantment;
62	};
63	
64	const sumBase = (items: Item[]): number =>
65	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
66	
67	const partitionByType = (items: Item[]): Item[][] => {
68	  const groups: Record<string, Item[]> = {};
69	  items.forEach((item) => (groups[item.type] ??= []).push(item));
70	  return Object.values(groups);
71	};
72	
73	const priceGroup = (group: Item[]): number =>
74	  group.length === BLOCK_SIZE && isComponent(group[0])
75	    ? BLOCK_PREMIUM
76	    : sumBase(group);
77	
78	const sumBasePremiums = (items: Item[]): number =>
79	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
80	
81	const isLoyalCustomer = (customer: Customer): boolean =>
82	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
83	
84	const applyPolicyModifiers = (
85	  base: number,
86	  customer: Customer,
87	  isFollowUp: boolean,
88	): number => {
89	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
90	  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
91	  const followUp = percentIf(isFollowUp, base, FOLLOWUP_DISCOUNT_PERCENT);
92	  return base + firstInsurance - loyalty - followUp;
93	};
94	
95	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number =>
96	  Math.ceil(applyPolicyModifiers(sumBasePremiums(items), customer, isFollowUp)) + PROCESSING_FEE;
97	
98	const executeStep = (
99	  step: Step,
100	  customer: Customer,
101	  isFollowUp: boolean,
102	): { premium: number } => ({
103	  premium: quotePremium(step.items ?? [], customer, isFollowUp),
104	});
105	
106	export const runScenario = (input: unknown): { results: unknown[] } => {
107	  const scenario = input as Scenario;
108	  let quoteCount = 0;
109	  return {
110	    results: scenario.steps.map((step) => {
111	      const isFollowUp = step.op === "quote" && quoteCount > 0;
112	      if (step.op === "quote") quoteCount++;
113	      return executeStep(step, scenario.customer, isFollowUp);
114	    }),
115	  };
116	};
